import React from "react";
import { NavLink, useNavigate } from "react-router-dom";

export default function AdminNavBar({ closeMobile }) {
  const role = localStorage.getItem("role");
  const navigate = useNavigate();

  if (role !== "Admin" && role !== "Academic Panel") return null;

  const logout = () => {
    localStorage.removeItem("role");
    navigate("/");
    window.location.reload();
  };

  const linkStyle = ({ isActive }) =>
    `block px-4 py-2 rounded-lg transition ${
      isActive
        ? "bg-indigo-600 text-white"
        : "text-gray-300 hover:bg-white/10"
    }`;

  return (
    <div className="h-full pt-20 px-4 relative">

      {/* HEADER */}
      <div className="mb-8">
        <h2 className="text-xl font-bold">
          {role === "Admin" ? "Admin Panel" : "Academic Panel"}
        </h2>
        <p className="text-xs text-gray-400">Smart Learning System</p>
      </div>

      {/* MENU */}
      <ul className="space-y-2">
        {role === "Admin" && (
          <>
            <li onClick={closeMobile}>
              <NavLink to="/admin/users" className={linkStyle}>
                👥 Users
              </NavLink>
            </li>
            <li onClick={closeMobile}>
              <NavLink to="/admin/reports" className={linkStyle}>
                📊 Reports
              </NavLink>
            </li>
            <li onClick={closeMobile}>
              <NavLink to="/admin/settings" className={linkStyle}>
                ⚙ Settings
              </NavLink>
            </li>
          </>
        )}

        {role === "Academic Panel" && (
          <>
            <li onClick={closeMobile}>
              <NavLink to="/resources" className={linkStyle}>
                📚 Resources
              </NavLink>
            </li>
            <li onClick={closeMobile}>
              <NavLink to="/tasks" className={linkStyle}>
                ✅ Tasks
              </NavLink>
            </li>
          </>
        )}
      </ul>

      {/* LOGOUT */}
      <div className="absolute bottom-6 left-0 w-full px-4">
        <button
          onClick={logout}
          className="w-full bg-red-500 hover:bg-red-600 py-2 rounded-lg"
        >
          Logout
        </button>
      </div>
    </div>
  );
}
